// linking.ts
import { LinkingOptions } from '@react-navigation/native';

const config = {
  screens: {
    Root: {
      screens: {
        Accueil: {
          screens: {
            ProductDetail: 'product/:productId',
            Home: 'home',
          },
        },
        Panier: 'cart',
        Profil: 'profile',
      },
    },
    Auth: {
      screens: {
        Login: 'login',
        Register: 'register',
      },
    },
  },
};

export const linking: LinkingOptions<RootStackParamList> = {
  prefixes: ['afrimarket://', 'https://afrimarket.com'],
  config,

  // Récupérer le produitId depuis l'URL
  getStateFromPath: (path, options) => {
    const match = path.match(/product\/(\d+)/);
    const productId = match ? parseInt(match[1], 10) : null;

    // Stocker pour utilisation ultérieure
    if (productId) {
      global.pendingProductId = productId;
    }

    return options.getStateFromPath(path, options);
  },
};

// App.tsx - Gestion de la redirection après connexion
import { useEffect, useContext, useRef } from 'react';
import { NavigationContainer } from '@react-navigation/native';

export default function App() {
  const navigationRef = useRef(null);
  const { user, isLoading } = useContext(AuthContext);
  const pendingProductIdRef = useRef(global.pendingProductId);

  useEffect(() => {
    // Après connexion, naviguer vers le produit en attente
    if (user && pendingProductIdRef.current && navigationRef.current) {
      navigationRef.current.navigate('Root', {
        screen: 'Accueil',
        params: {
          screen: 'ProductDetail',
          params: { productId: pendingProductIdRef.current }
        }
      });
      pendingProductIdRef.current = null;
      global.pendingProductId = null;
    }
  }, [user]);

  return (
    <NavigationContainer ref={navigationRef} linking={linking}>
      {/* ... */}
    </NavigationContainer>
  );
}

// productService.ts - Générer le lien de partage
export const generateShareLink = (productId: number): string => {
  return `afrimarket://product/${productId}`;
};

// Composant de partage
const handleShare = async (productId: number) => {
  const url = generateShareLink(productId);
  await Share.share({
    message: `Découvrez ce produit sur AfriMarket : ${url}`,
    title: 'Partager ce produit',
  });
};
